  ('optometrist-moex-03034', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '黃斑部病變患者，如其中心盲點為4度，建議字體在視網膜上成像的大小至少為何，患者始能分辨字形？', '["2度", "4度", "8度", "16度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "3d8d29219809", "answer_pdf_sha1": "34cf84e1e2dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03035', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '40公分處可辨識的2.0M 視標，相對於史耐倫（Snellen）視力表中那個視標？', '["20/20", "20/40", "20/50", "20/100"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "3d8d29219809", "answer_pdf_sha1": "34cf84e1e2dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03036', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '配戴高度數正鏡（plus lens）的患者，會遇到下列何種情況？', '["會有「枕形失真」（pincushion distortion）效應", "會降低最高視力值", "會產生環狀盲點", "有縮小影像的效果"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "3d8d29219809", "answer_pdf_sha1": "34cf84e1e2dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03037', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '下列關於手持式望遠鏡（telescope）的敘述，何者錯誤？', '["低視能患者看遠的輔具以望遠鏡為主", "相對於放大鏡是以靜態閱讀為主，望遠鏡則以進行時動態使用", "透過望遠鏡，遠物看起來很像在眼前，會影響使用者的空間距離判斷", "稍微移動望遠鏡會造成影像的快速移動，故容易追丟目標物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "3d8d29219809", "answer_pdf_sha1": "34cf84e1e2dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03038', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '下列關於鏡片的敘述，何者正確？', '["1×的放大鏡，以25公分的視物距離來說，相當於+2.5 D的透鏡", "2×的放大鏡，以40公分的視物距離來說，相當於+5.0 D的透鏡", "3×的放大鏡，以40公分的視物距離來說，相當於+12.0 D的透鏡", "4×的放大鏡，以25公分的視物距離來說，相當於+10.0 D的透鏡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "3d8d29219809", "answer_pdf_sha1": "34cf84e1e2dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03039', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '望遠鏡可以固定在一般眼鏡上，下列敘述何者錯誤？', '["其固定的位置，通常在眼鏡片的視軸線之下，以利行動", "望遠鏡是以放大視角達到看清遠物的效果", "行動時必須透過眼鏡片的視軸線及望遠鏡未被擋住的視野來辨識環境", "需要看清目標物如站牌或招牌等，可稍低頭透過望遠鏡放大來辨識"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "3d8d29219809", "answer_pdf_sha1": "34cf84e1e2dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03040', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '關於低視力病人的視覺功能評估敘述，下列何者正確？', '["Pelli–Robson表（Pelli–Robson chart）是評估遠距離視力的工具之一", "測量顏色覺時，照明狀態不必標準化，大概看得見就可以", "評估近距離視力（near acuity）時，也要同時評估病人閱讀的速度、能力和流暢度", "白內障和角膜結疤的病人不會有眩光（glare）的問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "3d8d29219809", "answer_pdf_sha1": "34cf84e1e2dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03041', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '配戴高度數正鏡的患者會遇到環狀盲區，下列敘述何者錯誤？', '["盲區的大小可由Prentice''s rule計算出來", "頂間距離愈大，盲區範圍愈大", "在1至3公尺的距離最明顯", "盲區的產生是無法被改善的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "3d8d29219809", "answer_pdf_sha1": "34cf84e1e2dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03042', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '關於站立式放大鏡（stand magnifier），下列何者錯誤？', '["站立式放大鏡的腳座高度，通常較鏡片的焦距長", "使用站立式放大鏡常需調視（accommodation），或併用近看眼鏡", "站立式放大鏡的實用放大倍率，會比其鏡片的放大倍率低", "相較於手持式放大鏡，建議使用較高倍率的站立式放大鏡，以獲得相同效果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "3d8d29219809", "answer_pdf_sha1": "34cf84e1e2dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03043', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '+3.00 D的遠視患者，因矯正視力僅0.1，需加上+10.00 D的閱讀鏡片（reading add），則其閱讀距離為何？', '["8 cm", "10 cm", "14 cm", "16 cm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "3d8d29219809", "answer_pdf_sha1": "34cf84e1e2dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
